<script setup lang="ts">
import { onMounted, reactive, ref } from 'vue'; import PageHeader from '@/components/PageHeader.vue'; import StatusTag from '@/components/StatusTag.vue'; import type { Batch } from '@/types'; import { createBatch, deleteBatch, getBatches, updateBatch } from '@/api/batches'; import { evidenceBatch } from '@/api/certificates'; import { ElMessage, ElMessageBox } from 'element-plus'
const loading=ref(false),dialog=ref(false),detail=ref(false),rows=ref<Batch[]>([]),total=ref(0),current=ref<Batch>();const query=reactive({current:1,size:10,keyword:'',status:''});const form=reactive<Batch>({batch_id:0,batch_no:'',batch_name:'',project_name:'',template_id:1,student_count:0,generated:0,evidenced:0,status:'DRAFT'})
async function load(){loading.value=true;try{const p=await getBatches(query);rows.value=p.records;total.value=p.total}catch{rows.value=[]}finally{loading.value=false}}function reset(){query.keyword='';query.status='';query.current=1;load()}function open(row?:Batch){Object.assign(form,row||{batch_id:0,batch_no:'',batch_name:'',project_name:'',template_id:1,student_count:0,generated:0,evidenced:0,status:'DRAFT'});dialog.value=true}
async function save(){if(!form.batch_name||!form.project_name)return ElMessage.warning('请填写批次名称和项目名称');if(form.batch_id)await updateBatch(form.batch_id,form);else await createBatch(form);ElMessage.success('保存成功');dialog.value=false;load()}async function remove(row:Batch){await ElMessageBox.confirm(`确认删除批次“${row.batch_name}”吗？`,'删除批次',{type:'warning'});await deleteBatch(row.batch_id);ElMessage.success('删除成功');load()}async function evidence(row:Batch){await evidenceBatch(row.batch_id);ElMessage.success('批量存证任务已提交');load()}function show(row:Batch){current.value=row;detail.value=true}onMounted(load)
</script>
<template><div><PageHeader title="证书批次" description="组织批量签发与批量存证"><el-button type="primary" @click="open()">创建批次</el-button></PageHeader><section class="panel"><div class="toolbar"><el-input v-model="query.keyword" placeholder="批次编号、名称或项目" clearable style="width:280px"/><el-select v-model="query.status" placeholder="状态" clearable style="width:150px"><el-option v-for="s in ['DRAFT','IMPORTED','GENERATED','EVIDENCED','COMPLETED','CANCELLED']" :key="s" :label="s" :value="s"/></el-select><el-button type="primary" @click="query.current=1;load()">查询</el-button><el-button @click="reset">重置</el-button></div><el-table v-loading="loading" :data="rows" empty-text="暂无批次数据"><el-table-column prop="batch_no" label="批次编号" min-width="170"/><el-table-column prop="batch_name" label="批次名称" min-width="190"/><el-table-column prop="project_name" label="实训项目" min-width="190"/><el-table-column prop="student_count" label="学生数"/><el-table-column label="生成进度"><template #default="s"><el-progress :percentage="s.row.student_count?Math.round(s.row.generated/s.row.student_count*100):0"/></template></el-table-column><el-table-column label="存证进度"><template #default="s"><el-progress :percentage="s.row.student_count?Math.round(s.row.evidenced/s.row.student_count*100):0" color="#059669"/></template></el-table-column><el-table-column label="状态"><template #default="s"><StatusTag :value="s.row.status"/></template></el-table-column><el-table-column label="操作" width="240"><template #default="s"><el-button link type="primary" @click="show(s.row)">详情</el-button><el-button link type="primary" @click="open(s.row)">编辑</el-button><el-button link type="success" @click="evidence(s.row)">批量存证</el-button><el-button link type="danger" @click="remove(s.row)">删除</el-button></template></el-table-column></el-table><div class="pagination"><el-pagination v-model:current-page="query.current" v-model:page-size="query.size" :total="total" layout="total, sizes, prev, pager, next" @change="load"/></div></section><el-dialog v-model="dialog" :title="form.batch_id?'编辑批次':'创建批次'" width="560"><el-form label-position="top"><el-form-item label="批次名称" required><el-input v-model="form.batch_name"/></el-form-item><el-form-item label="实训项目" required><el-input v-model="form.project_name"/></el-form-item><el-form-item label="模板ID"><el-input-number v-model="form.template_id" :min="1"/></el-form-item></el-form><template #footer><el-button @click="dialog=false">取消</el-button><el-button type="primary" @click="save">保存</el-button></template></el-dialog><el-drawer v-model="detail" title="批次详情"><div v-if="current" class="detail-list"><div><span>批次编号</span><b>{{current.batch_no}}</b></div><div><span>批次名称</span><b>{{current.batch_name}}</b></div><div><span>项目</span><b>{{current.project_name}}</b></div><div><span>学生数</span><b>{{current.student_count}}</b></div></div></el-drawer></div></template>